  "verses": [
    {
      "n": 47,
      "column": "left",
      "text": "Un wiſſi ſchee Pulki atſihs/ \nka tas KUNGS ne iſglahbjzaur\nSohbinn jeb zaur Schkehpu : \nJo tas Karſch peederr tam KUN-\nGAM / tas dohs juhs muhſtu\nRohkā."
    },
    {
      "n": 48,
      "column": "left",
      "text": "Rad nu tas Wilisteris\nzehlehs/ un gabje/ un tuwu pee\nDahwida nahze / tad ſteidsahs\nDahwids/ un tezzeja vee teem\nKara- Pulkeem prett to Wili-\nsteri."
    },
    {
      "n": 49,
      "column": "left",
      "text": "Un Dahwids bahſe farwu\nRohku eekſch to Kalliti / un reh-\nme no turren weenu Akimini/ un\nmette ar Lingu/ un ceſweede tam\nWilisteram paſchā Peerē/ ta ka\ntas Akmins winna Peerē eeſfrehe-\nje/ un tas kritte us farwu Waigu\npee Senmes."
    },
    {
      "n": 50,
      "column": "left",
      "text": "Ta pahrwarreja Dah-\nwids to Wilistert ar weenu Lingu/\nun ar weenu Akimini/ un kawe\nto Wilisteri/ un nokawe to/ Bet\nDahwidam ne bija Sohbins\nRohkā,"
    },
    {
      "n": 51,
      "column": "left",
      "text": "Tapehz tezzeja Dahwids/\nun ſtahweja us to Wilisteri / un\nachtme winna Sohbinnu / un iſ-\nwilke to no farwahn Maksimi/un\nnokawe to/ un nozirte tam to\nlivu ar to. Rad nu tee Wili-"
    },
    {
      "n": 52,
      "column": "right",
      "text": "Un Israēta Wihri ir Ju-\nda zehlehs/ un gawileja/ un dſi-\nnahs teem Wilistexeem pakka-\nkamehr nahk us to Eeleiju/un lih-\npafchahin Ekrona Wahrtim / u-\nto Wilisteru Eewainoti kritte\n to Zeltu Saärim/ un lihds Ga-\ntai un lihds Ekroam."
    },
    {
      "n": 53,
      "column": "right",
      "text": "Pehz atgreesehs Israē-\nBehrni no to Wilistern Pakka-\ndsihfchanas/ un aplanpija win-\nLehgerus."
    },
    {
      "n": 54,
      "column": "right",
      "text": "Un Dahwids nehme\nWilistera Galwu/ un nehfe to u-\nJerusalemi/ bet winna Bruwa-\nlikke winch fawa Telti."
    },
    {
      "n": 55,
      "column": "right",
      "text": "Rad Sauls redseja\nDahwidu iſeijam prett to Wi-\nsteri / fazzija tas us Abneru\nKara Leeln- Kungu : Ka De-\nirr ſchis Puifis Abners? tad fo-\nzija Abners : Tik teefcham ka t-\nwa Dwehfele dſihwo/ Kehninſc-\nes to ne finnu."
    },
    {
      "n": 56,
      "column": "right",
      "text": "Tad fazzija tas Kehninſc-\nWaiza jelle/ ka Dehls ſchis Ja-\nnekis irr?"
    },
    {
      "n": 57,
      "column": "right",
      "text": "Rad nu Dahwids afgr-\nſehs no ta Wilistera Kanſch-\nnas/ nehine Abners winnu / 1-\nwedde winnu preekſch Saula/\nta Wilistera Galwa bija win-\nRohkā."
    },
    {
      "n": 58,
      "column": "right",
      "text": "Un Sauls fazzija us t-\nKa Dehls effi tu Puifis? Da-\nwids fazzija : Es efinu we-\nDehls tawa Kalpa Jsaja ta B-\nlemitera."
    }
  ],
